import * as crypto from 'crypto';
import { execSync } from 'child_process';
import { ProcessMonitor } from '../process-monitor';
import { createTask, updateTaskStatus } from '../api-client';
import { createLogger } from '../logger';
import { TaskStatus } from '../../shared/types';

function resolveCommand(cmd: string): string {
  try {
    return execSync(`which ${cmd}`, { encoding: 'utf-8' }).trim();
  } catch {
    return cmd;
  }
}

export async function runCommand(args: string[]): Promise<void> {
  // Parse --idle-timeout and --name flags
  let idleTimeout: number | undefined;
  let taskName: string | undefined;
  const commandArgs: string[] = [];
  let i = 0;

  while (i < args.length) {
    if (args[i] === '--idle-timeout' && i + 1 < args.length) {
      idleTimeout = parseInt(args[i + 1], 10);
      i += 2;
    } else if (args[i] === '--name' && i + 1 < args.length) {
      taskName = args[i + 1];
      i += 2;
    } else {
      commandArgs.push(args[i]);
      i++;
    }
  }

  if (commandArgs.length === 0) {
    console.error('Usage: pmon run [--idle-timeout <seconds>] [--name <name>] <command> [args...]');
    process.exit(1);
  }

  const command = commandArgs[0];
  const cmdArgs = commandArgs.slice(1);
  const resolvedCommand = resolveCommand(command);
  const taskId = crypto.randomUUID();
  const logger = createLogger(taskId);

  if (resolvedCommand === command) {
    // which didn't find it, check if it exists at all
    try {
      execSync(`which ${command}`, { encoding: 'utf-8' });
    } catch {
      console.error(`[pmon] Command not found: ${command}`);
      process.exit(127);
    }
  }

  logger.info(`Starting: ${resolvedCommand} ${cmdArgs.join(' ')}`);

  // Try to load node-pty, fall back to child_process
  let pty: typeof import('node-pty') | null = null;
  try {
    pty = require('node-pty');
  } catch {
    logger.warn('node-pty not available, falling back to child_process.spawn');
  }

  // Register task with main app
  const task = await createTask({
    command,
    args: cmdArgs,
    name: taskName,
    pid: process.pid,
    idleTimeout,
  });

  const registeredId = task?.id ?? taskId;
  let appConnected = task !== null;

  if (!appConnected) {
    console.warn('[pmon] Warning: Could not connect to ProgressMachine app. Task will run without monitoring UI.');
    logger.warn('Could not connect to main app');
  }

  // Set up process monitor
  const monitor = new ProcessMonitor(
    {
      onStatusChange: async (status: TaskStatus, lastOutput: string[]) => {
        logger.info(`Status changed: ${status}`);
        if (appConnected) {
          const result = await updateTaskStatus(registeredId, {
            status,
            lastOutput,
            lastActivityAt: Date.now(),
          });
          if (!result) appConnected = false;
        }
      },
      onExit: async (code: number | null) => {
        logger.info(`Process exited with code: ${code}`);
        if (appConnected) {
          await updateTaskStatus(registeredId, {
            status: 'exited',
            exitCode: code ?? undefined,
            lastOutput: monitor.getLastOutput(),
            lastActivityAt: Date.now(),
          });
        }
      },
    },
    idleTimeout,
  );

  // Spawn the process
  spawnWithPty(pty, resolvedCommand, cmdArgs, monitor, logger);
}

function spawnWithFallback(resolvedCommand: string, cmdArgs: string[], monitor: ProcessMonitor, logger: ReturnType<typeof createLogger>): void {
  const { spawn } = require('child_process');
  const child = spawn(resolvedCommand, cmdArgs, {
    stdio: ['pipe', 'pipe', 'pipe'],
    cwd: process.cwd(),
    env: process.env,
  });

  child.stdout.on('data', (data: Buffer) => {
    process.stdout.write(data);
    monitor.handleOutput(data.toString());
  });

  child.stderr.on('data', (data: Buffer) => {
    process.stderr.write(data);
    monitor.handleOutput(data.toString());
  });

  child.on('close', (code: number | null) => {
    monitor.handleExit(code);
    process.exit(code ?? 1);
  });

  process.stdin.pipe(child.stdin);
  process.on('SIGINT', () => child.kill('SIGINT'));
  process.on('SIGTERM', () => child.kill('SIGTERM'));
}

function spawnWithPty(
  pty: typeof import('node-pty') | null,
  resolvedCommand: string,
  cmdArgs: string[],
  monitor: ProcessMonitor,
  logger: ReturnType<typeof createLogger>,
): void {
  if (pty) {
    try {
      const cols = process.stdout.columns || 80;
      const rows = process.stdout.rows || 24;
      const shell = pty.spawn(resolvedCommand, cmdArgs, {
        name: 'xterm-color',
        cols,
        rows,
        cwd: process.cwd(),
        env: process.env as Record<string, string>,
      });

      // Update pty size when terminal resizes
      process.stdout.on('resize', () => {
        shell.resize(process.stdout.columns || 80, process.stdout.rows || 24);
      });

      shell.onData((data: string) => {
        process.stdout.write(data);
        monitor.handleOutput(data);
      });

      shell.onExit(({ exitCode }: { exitCode: number }) => {
        monitor.handleExit(exitCode);
        process.exit(exitCode);
      });

      // Forward stdin to the pty
      if (process.stdin.isTTY) {
        process.stdin.setRawMode(true);
      }
      process.stdin.resume();
      process.stdin.on('data', (data: Buffer) => {
        shell.write(data.toString());
      });

      // Handle SIGINT/SIGTERM
      process.on('SIGINT', () => shell.kill('SIGINT'));
      process.on('SIGTERM', () => shell.kill('SIGTERM'));
      return;
    } catch (err) {
      logger.warn(`node-pty spawn failed: ${err}, falling back to child_process`);
    }
  }

  // Fallback: child_process.spawn
  spawnWithFallback(resolvedCommand, cmdArgs, monitor, logger);
}
